import React from 'react';
import { Box, Typography, styled, alpha, Paper, Tabs, Tab, Skeleton } from '@mui/material';
import { CarSpecifications } from '../types';

interface CarSpecificationsIconsProps {
  engine?: string;
  power?: string;
  acceleration?: string;
  maxSpeed?: string;
  color?: string;
  year?: number;
  carSpecifications?: CarSpecifications | null;
  showTabs?: boolean;
  isLoading?: boolean;
}

const SpecCard = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(3),
  boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
  overflow: 'hidden',
}));

const SpecContainer = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexWrap: 'wrap',
  justifyContent: 'space-around',
  gap: theme.spacing(2),
  '& > div': {
    flex: '1 1 120px',
    maxWidth: '150px',
    textAlign: 'center',
  }
}));

const SpecItem = styled(Box)(({ theme }) => ({
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  textAlign: 'center',
  padding: theme.spacing(1.5),
  borderRadius: theme.spacing(2),
  backgroundColor: alpha(theme.palette.primary.main, 0.05),
  transition: 'all 0.2s ease',
  '&:hover': {
    transform: 'translateY(-3px)',
    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
    backgroundColor: alpha(theme.palette.primary.main, 0.08),
  },
  '& .icon': {
    color: theme.palette.primary.main,
    marginBottom: theme.spacing(1),
    fontSize: '1.7rem',
  },
}));

const StyledTabs = styled(Tabs)(({ theme }) => ({
  marginBottom: theme.spacing(3),
  '& .MuiTabs-indicator': {
    backgroundColor: theme.palette.primary.main,
    height: 3,
    borderRadius: 3,
  },
  '& .MuiTab-root': {
    textTransform: 'none',
    fontWeight: 600,
    fontSize: '0.9rem',
    minHeight: 40,
    [theme.breakpoints.down('sm')]: {
      padding: '6px 10px',
      minWidth: 'auto',
    },
  },
}));

const CarSpecificationsIcons: React.FC<CarSpecificationsIconsProps> = ({
  engine,
  power,
  acceleration,
  maxSpeed,
  color,
  year,
  carSpecifications,
  showTabs = true,
  isLoading = false
}) => {
  const [tabValue, setTabValue] = React.useState(0);

  const handleTabChange = (_: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };

  // Если данные загружаются, показываем скелетон
  if (isLoading) {
    return (
      <SpecCard>
        {showTabs && (
          <StyledTabs
            value={0}
            variant="scrollable"
            scrollButtons="auto"
          >
            <Tab label="Характеристики" />
            <Tab label="Комплектация" />
          </StyledTabs>
        )}
        
        <SpecContainer>
          {[...Array(6)].map((_, index) => (
            <Box key={index}>
              <SpecItem>
                <Skeleton variant="circular" width={40} height={40} sx={{ mb: 1 }} />
                <Skeleton variant="text" width={100} />
                <Skeleton variant="text" width={80} height={30} />
              </SpecItem>
            </Box>
          ))}
        </SpecContainer>
      </SpecCard>
    );
  }

  // Проверяем, есть ли данные из базы
  const hasDBSpecs = carSpecifications !== null && carSpecifications !== undefined;

  // Данные для отображения
  // 1. Двигатель - берем из БД, если есть, или из пропса
  let displayEngine = engine || '';
  if (hasDBSpecs && carSpecifications?.engine) {
    const engineObj = carSpecifications.engine;
    displayEngine = engineObj.type || '';
    if (engineObj.displacement) {
      displayEngine += ` ${engineObj.displacement}`;
    }
  }

  // 2. Мощность - берем из БД, если есть, или из пропса
  let displayPower = power || '';
  if (hasDBSpecs) {
    if (carSpecifications?.power) {
      displayPower = carSpecifications.power;
    } else if (carSpecifications?.engine?.horsepower) {
      displayPower = `${carSpecifications.engine.horsepower} л.с.`;
    }
  }

  // 3. Разгон - берем из БД, если есть, или из пропса
  const displayAcceleration = hasDBSpecs && carSpecifications?.acceleration
    ? carSpecifications.acceleration
    : acceleration || '';

  // 4. Максимальная скорость - берем из БД, если есть, или из пропса
  const displayMaxSpeed = hasDBSpecs && carSpecifications?.topSpeed
    ? carSpecifications.topSpeed
    : maxSpeed || '';

  // 5. Цвет - берем из БД, если есть, или из пропса
  const displayColor = hasDBSpecs && carSpecifications?.exteriorColor
    ? carSpecifications.exteriorColor
    : color || '';

  // 6. Год - берем из БД, если есть, или из пропса
  const displayYear = hasDBSpecs && carSpecifications?.year
    ? carSpecifications.year
    : year || new Date().getFullYear();
    
  // 7. Трансмиссия - берем из БД, если есть
  const displayTransmission = hasDBSpecs && carSpecifications?.transmission
    ? carSpecifications.transmission
    : '';
    
  // 8. Привод - берем из БД, если есть 
  const displayDrivetrain = hasDBSpecs && carSpecifications?.drivetrain
    ? carSpecifications.drivetrain
    : '';
    
  // 9. Топливо - берем из БД, если есть
  const displayFuel = hasDBSpecs && carSpecifications?.fuel
    ? carSpecifications.fuel
    : '';
  
  // Функция для отображения иконки в зависимости от типа характеристики
  const getIcon = (type: string) => {
    switch(type) {
      case 'engine':
        return "⛽";
      case 'power':
        return "⚡";
      case 'acceleration':
        return "⏱️";
      case 'maxSpeed':
        return "🚀";
      case 'color':
        return "🎨";
      case 'year':
        return "📆";
      case 'transmission':
        return "⚙️";
      case 'drivetrain':
        return "🔄";
      case 'fuel':
        return "🔋";
      default:
        return "🔍";
    }
  };

  // Создание структуры данных для удобного отображения
  const specsData = [
    { type: 'engine', label: 'Двигатель', value: displayEngine || "4.4L V8 Twin-Turbo" },
    { type: 'power', label: 'Мощность', value: displayPower || "625 л.с." },
    { type: 'acceleration', label: 'Разгон до 100 км/ч', value: displayAcceleration || "3.8 с до 100 км/ч" },
    { type: 'maxSpeed', label: 'Макс. скорость', value: displayMaxSpeed || "290 км/ч" },
    { type: 'color', label: 'Цвет', value: displayColor || "Черный металлик" },
    { type: 'year', label: 'Год выпуска', value: displayYear || 2023 }
  ];
  
  // Добавляем дополнительные характеристики из БД, если они есть
  if (displayTransmission) {
    specsData.push({ type: 'transmission', label: 'Трансмиссия', value: displayTransmission });
  }
  if (displayDrivetrain) {
    specsData.push({ type: 'drivetrain', label: 'Привод', value: displayDrivetrain });
  }
  if (displayFuel) {
    specsData.push({ type: 'fuel', label: 'Топливо', value: displayFuel });
  }

  const specsContent = (
    <SpecContainer>
      {specsData.map((spec, index) => (
        <Box key={index}>
          <SpecItem>
            <Box className="icon">{getIcon(spec.type)}</Box>
            <Typography variant="body2" color="text.secondary">
              {spec.label}
            </Typography>
            <Typography variant="body1" fontWeight={600}>
              {spec.value}
            </Typography>
          </SpecItem>
        </Box>
      ))}
    </SpecContainer>
  );

  if (!showTabs) {
    return specsContent;
  }

  return (
    <SpecCard>
      <StyledTabs
        value={tabValue}
        onChange={handleTabChange}
        variant="scrollable"
        scrollButtons="auto"
      >
        <Tab label="Характеристики" />
        <Tab label="Комплектация" />
      </StyledTabs>

      <Box role="tabpanel" hidden={tabValue !== 0}>
        {tabValue === 0 && specsContent}
      </Box>

      <Box role="tabpanel" hidden={tabValue !== 1}>
        {tabValue === 1 && (
          <Box>
            {hasDBSpecs && carSpecifications?.features && carSpecifications.features.length > 0 ? (
              <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1 }}>
                {carSpecifications.features.map((feature, index) => (
                  <Box 
                    key={index} 
                    sx={{ 
                      p: 1.5, 
                      borderRadius: 2, 
                      bgcolor: alpha('#2196F3', 0.05),
                      display: 'flex',
                      alignItems: 'center'
                    }}
                  >
                    <Box 
                      sx={{ 
                        mr: 2, 
                        width: 24, 
                        height: 24, 
                        borderRadius: '50%', 
                        bgcolor: 'primary.main', 
                        color: 'white',
                        display: 'flex',
                        alignItems: 'center',
                        justifyContent: 'center',
                        fontSize: '0.8rem',
                        fontWeight: 'bold'
                      }}
                    >
                      {index + 1}
                    </Box>
                    <Typography variant="body1">
                      {feature}
                    </Typography>
                  </Box>
                ))}
              </Box>
            ) : (
              <Typography variant="body1" color="text.secondary" sx={{ textAlign: 'center', py: 4 }}>
                Информация о комплектации будет доступна позже
              </Typography>
            )}
          </Box>
        )}
      </Box>
    </SpecCard>
  );
};

export default CarSpecificationsIcons;
